const items = $input.all();
const total = items.length;

let publicadosTotais = 0;
let publicadosParciais = 0;
let bloqueadosKillcritic = 0;
let pendentesCredencial = 0;
let falhasTecnicas = 0;

let jornalisticasCount = 0;
let institucionaisCount = 0;
let educativosCount = 0;

items.forEach(item => {
  const row = item.json;

  if (row.status_global === 'publicado_total') publicadosTotais++;
  else if (row.status_global === 'publicado_parcial') publicadosParciais++;
  else if (row.status_global === 'bloqueado_revisao') bloqueadosKillcritic++;
  else if (row.status_global === 'pendente_credencial') pendentesCredencial++;
  else if (row.status_global === 'falhou_total') falhasTecnicas++;

  if (row.fonte_tipo === 'noticias') jornalisticasCount++;
  else if (row.fonte_tipo === 'institucional') institucionaisCount++;
  else educativosCount++;
});

const reportHtml = `
  <h2>Relatório Semanal de Publicações Sociais (DL Soluções)</h2>
  <p><b>Período:</b> Últimos 7 dias</p>
  <p><b>Total de Postagens Processadas:</b> ${total}</p>
  <hr/>
  <h3>Resumo de Publicações (Status Global):</h3>
  <ul>
    <li><b>Publicados Totais (Todos os canais ativos):</b> ${publicadosTotais}</li>
    <li><b>Publicados Parciais (Alguns canais ativos):</b> ${publicadosParciais}</li>
    <li><b>Bloqueados por KILLCRITIC:</b> ${bloqueadosKillcritic}</li>
    <li><b>Pendentes por Credencial:</b> ${pendentesCredencial}</li>
    <li><b>Falhas Técnicas Totais:</b> ${falhasTecnicas}</li>
  </ul>
  <hr/>
  <h3>Estatísticas de Origem de Conteúdo:</h3>
  <ul>
    <li><b>Fontes Jornalísticas Usadas:</b> ${jornalisticasCount}</li>
    <li><b>Fontes Institucionais Usadas:</b> ${institucionaisCount}</li>
    <li><b>Posts Educativos Evergreen:</b> ${educativosCount}</li>
  </ul>
`;

const reportTelegram = `📊 *Relatório Semanal — Autopublicação Social DL*

*Total Processado:* ${total}

*Resumo de Status Global:*
- ✅ Publicações Totais: ${publicadosTotais}
- ⚠️ Publicações Parciais: ${publicadosParciais}
- ⛔ Bloqueados por KILLCRITIC: ${bloqueadosKillcritic}
- 🔑 Pendentes por Credencial: ${pendentesCredencial}
- ❌ Falhas Técnicas Totais: ${falhasTecnicas}

*Fontes de Conteúdo Utilizadas:*
- 📰 Jornalísticas (G1, etc.): ${jornalisticasCount}
- 🏛️ Institucionais (ABESE/CREA): ${institucionaisCount}
- 💡 Educativos Evergreen: ${educativosCount}`;

return [{
  json: {
    report_html: reportHtml,
    report_telegram: reportTelegram
  }
}];
